ას.","law_article":"მუხლი 260"},{"text":"რას ეხება სსკ-ის 276-ე მუხლი?","options":["ტრანსპორტის მოძრაობის უსაფრთხოების ან ექსპლუატაციის წესის დარღვევას","სატრანსპორტო საშუალების უხარისხო რემონტს","ტრანსპორტის ექსპლუატაციისათვის გაუვარგისებას","მატარებლის თვითნებურ გაჩერებას"],"correct_option":"A","explanation":"276-ე მუხლი ითვალისწინებს ტრანსპორტის მოძრაობის უსაფრთხოების ან ექსპლუატაციის წესის დარღვევას.","law_article":"მუხლი 276"},{"text":"რას ეხება სსკ-ის 284-ე მუხლი?","options":["კომპიუტერულ სისტემაში უნებართვო შეღწევას","კომპიუტერული სისტემის უკანონოდ გამოყენებას","კომპიუტერული მონაცემის ხელყოფას","ყალბი ოფიციალური კომპიუტერული მონაცემის შექმნას"],"correct_option":"A","explanation":"284-ე მუხლი ითვალისწინებს კომპიუტერულ სისტემაში უნებართვო შეღწევას.","law_article":"მუხლი 284"},{"text":"რას ეხება სსკ-ის 285-ე მუხლი?","options":["კომპიუტერული მონაცემის ან/და კომპიუტერული სისტემის უკანონოდ გამოყენებას","კომპიუტერულ სისტემაში უნებართვო შეღწევას","კომპიუტერული მონაცემის ხელყოფას ფინანსური სარგებლის მიზნით","ყალბი ოფიციალური მონაცემის შექმნას"],"correct_option":"A","explanation":"285-ე მუხლი ითვალისწინებს კომპიუტერული მონაცემის ან/და კომპიუტერული სისტემის უკანონოდ გამოყენებას.","law_article":"მუხლი 285"},{"text":"რას ეხება სსკ-ის 300-ე მუხლი?","options":["უკანონო თევზჭერას","უკანონო ნადირობას","ზღვის დაბინძურებას","წყლით სარგებლობის წესის დარღვევას"],"correct_option":"A","explanation":"300-ე მუხლი ითვალისწინებს უკანონო თევზჭერას.","law_article":"მუხლი 300"},{"text":"რას ეხება სსკ-ის 301-ე მუხლი?","options":["უკანონო ნადირობას","უკანონო თევზჭერას","ცხოველის წამებას","ბუნების ძეგლის დაზიანებას"],"correct_option":"A","explanation":"301-ე მუხლი ითვალისწინებს უკანონო ნადირობას.","law_article":"მუხლი 301"}]$questions$::jsonb)
  loop
    select id into v_question_id
    from public.questions
    where law_id = v_law_id
      and text = r.question->>'text';

    if v_question_id is null then
      select id into v_article_id
      from public.law_articles
      where law_id = v_law_id
        and article_number = regexp_replace(
          r.question->>'law_article',
          '^(მუხლი[[:space:]]+[^,[:space:]]+).*$',
          '\1'
        );

      insert into public.questions (
        category_id, subcategory_id, law_id, primary_law_article_id, text, difficulty,
        explanation, law_name, law_article, source_url, law_version_date,
        needs_review, is_prime, is_published
      )
      values (
        v_category_id, v_subcategory_id, v_law_id, v_article_id,
        r.question->>'text', 'hard', r.question->>'explanation',
        'საქართველოს სისხლის სამართლის კოდექსი', r.question->>'law_article',
        v_source_url, v_version_date, true, false, false
      )
      returning id into v_question_id;

      insert into public.question_options (question_id, option_text, is_correct, sort_order)
      select
        v_question_id,
        option.value,
        case option.ordinality
          when 1 then r.question->>'correct_option' = 'A'
          when 2 then r.question->>'correct_option' = 'B'
          when 3 then r.question->>'correct_option' = 'C'
          when 4 then r.question->>'correct_option' = 'D'
        end,
        option.ordinality
      from jsonb_array_elements_text(r.question->'options') with ordinality as option(value, ordinality);

      if v_article_id is not null then
        insert into public.question_law_articles (question_id, law_article_id, is_primary)
        values (v_question_id, v_article_id, true)
        on conflict (question_id, law_article_id) do nothing;
      end if;
    end if;
  end loop;
end $$;
